   input [width-1:0]  a, b; 
   input                     clk;
  wire _tap_clk = clk & {1{1'b1}};

   output [width-1:0] q; 
   reg [width-1:0]    res; 

   assign                    q = res;


   always @(posedge clk) begin
     res <= a-b;
   end

